<?php namespace App\Services\Cache; use Illuminate\Support\Facades\Redis; use Illuminate\Support\Facades\Log; use Exception; class RedisAdapter { public function get(string $key, $default = null) { try { return Redis::get($key) ?? $default; } catch (Exception $e) { Log::error('Redis Get Error: ' . $e->getMessage()); return $default; } } public function set(string $key, $value, int $ttl = 3600): bool { try { Redis::setex($key, $ttl, serialize($value)); return true; } catch (Exception $e) { Log::error('Redis Set Error: ' . $e->getMessage()); return false; } } public function forget(string $key): bool { try { return (bool) Redis::del($key); } catch (Exception $e) { Log::error('Redis Forget Error: ' . $e->getMessage()); return false; } } public function tags(array $tags): self { // التوسع في دعم الوسوم وفقاً لمتطلبات Redis return $this; } public function flush(): bool { try { Redis::flushdb(); return true; } catch (Exception $e) { Log::error('Redis Flush Error: ' . $e->getMessage()); return false; } } }